components.CityWeatherCard:
interface Props {
  city: string;
  tempF: number;
  condition: string;
  emoji: string;
  badge?: string;
  badgeColor?: string;
  accentColor?: string;
}

export default function CityWeatherCard({ city, tempF, condition, emoji, badge, badgeColor, accentColor = "#2563eb" }: Props) {
  const tempC = Math.round((tempF - 32) * 5 / 9);
  return (
    <div style={{
      background: "#ffffff",
      border: `2px solid ${accentColor}22`,
      borderRadius: 16,
      padding: "28px 24px",
      display: "flex",
      flexDirection: "column",
      alignItems: "center",
      gap: 10,
      boxShadow: "0 2px 12px 0 rgba(0,0,0,0.07)",
      position: "relative",
      minWidth: 160,
      flex: 1,
    }}>
      {badge && (
        <div style={{
          position: "absolute",
          top: 12,
          right: 14,
          background: badgeColor || accentColor,
          color: "#fff",
          borderRadius: 20,
          padding: "2px 12px",
          fontSize: 11,
          fontWeight: 700,
          letterSpacing: 0.5,
        }}>{badge}</div>
      )}
      <div style={{ fontSize: 48, lineHeight: 1 }}>{emoji}</div>
      <div style={{ fontSize: 22, fontWeight: 800, color: "#171717", fontFamily: "Geist, sans-serif" }}>{city}</div>
      <div style={{ fontSize: 40, fontWeight: 700, color: accentColor, lineHeight: 1.1 }}>{tempF}°F</div>
      <div style={{ fontSize: 18, color: "#64748b", fontWeight: 500 }}>{tempC}°C</div>
      <div style={{
        background: `${accentColor}18`,
        color: accentColor,
        borderRadius: 8,
        padding: "4px 16px",
        fontSize: 14,
        fontWeight: 600,
        marginTop: 4,
      }}>{condition}</div>
    </div>
  );
}

components.WeatherBarChart:
interface Props {
  cities: string[];
  temps: number[];
  colors: string[];
}

export default function WeatherBarChart({ cities = [], temps = [], colors = [] }: Props) {
  const max = Math.max(...temps, 1);
  const chartHeight = 180;
  const barWidth = 60;
  const gap = 40;
  const paddingLeft = 40;
  const paddingBottom = 40;
  const paddingTop = 20;
  const totalWidth = paddingLeft + cities.length * (barWidth + gap) + gap;
  const totalHeight = chartHeight + paddingBottom + paddingTop;

  return (
    <svg width="100%" viewBox={`0 0 ${totalWidth} ${totalHeight}`} style={{ display: "block", maxWidth: 420, margin: "0 auto" }}>
      {[0, 25, 50, 75, 100].map((pct) => {
        const y = paddingTop + chartHeight - (pct / 100) * chartHeight;
        const tempVal = Math.round((pct / 100) * max);
        return (
          <g key={pct}>
            <line x1={paddingLeft} y1={y} x2={totalWidth - gap / 2} y2={y} stroke="#e2e8f0" strokeWidth="1" />
            <text x={paddingLeft - 6} y={y + 4} textAnchor="end" fontSize="10" fill="#64748b">{tempVal}°F</text>
          </g>
        );
      })}
      {cities.map((city, i) => {
        const barHeight = (temps[i] / max) * chartHeight;
        const x = paddingLeft + gap / 2 + i * (barWidth + gap);
        const y = paddingTop + chartHeight - barHeight;
        return (
          <g key={city}>
            <rect x={x} y={y} width={barWidth} height={barHeight} rx="6" fill={colors[i]} opacity="0.9" />
            <text x={x + barWidth / 2} y={y - 6} textAnchor="middle" fontSize="12" fontWeight="bold" fill={colors[i]}>{temps[i]}°F</text>
            <text x={x + barWidth / 2} y={paddingTop + chartHeight + 18} textAnchor="middle" fontSize="12" fill="#171717">{city}</text>
          </g>
        );
      })}
    </svg>
  );
}

